// alertIsUrgent determines if the alert should be announced with higher priority.
func alertIsUrgent(variant AlertVariant) bool {
	return variant == AlertDanger || variant == AlertWarning
}

// alpineData generates the Alpine.js data initialization with timeout support.
func alpineData(prop AlertProp) string {
	// Create Alpine.js data object with show state and optional timeout
	if prop.DismissTimeout > 0 {
		// Auto-dismiss version with timeout
		return fmt.Sprintf("{ show: true, init() { setTimeout(() => { this.show = false }, %d) } }", prop.DismissTimeout)
	}
	return "{ show: true }"
}

// alertIdCounter is an atomic counter for generating unique alert IDs.
var alertIdCounter atomic.Uint64

// alertUniqueId generates a unique ID suffix or returns the provided ID.
// This ensures ARIA attributes have unique references even without explicit IDs.
func alertUniqueId(id string) string {
	if id != "" {
		return id
	}
	return fmt.Sprintf("a%d", alertIdCounter.Add(1))
}

// alertStatus returns the appropriate status attribute value based on variant.
func alertStatus(variant AlertVariant) string {
	switch variant {
	case AlertSuccess:
		return "success"
	case AlertWarning:
		return "warning"
	case AlertDanger:
		return "error"
	case AlertInfo:
		return "info"
	default:
		return "info"
	}
}

// alertClass generates the CSS class for the alert based on variant and shape.
// This uses a strings.Builder for better performance with multiple concatenations.
func alertClass(prop AlertProp) string {
	var sb strings.Builder
	sb.WriteString("alert")

	// Severity class
	switch prop.Variant {
	case AlertSuccess:
		sb.WriteString(" alert--success")
	case AlertWarning:
		sb.WriteString(" alert--warning")
	case AlertDanger:
		sb.WriteString(" alert--danger")
	case AlertInfo:
		sb.WriteString(" alert--info")
	default:
		sb.WriteString(" alert--info")
	}

	// Shape class
	switch prop.Shape {
	case AlertOutlined:
		sb.WriteString(" alert--outlined")
	case AlertFilled:
		sb.WriteString(" alert--filled")
	default:
		sb.WriteString(" alert--standard")
	}

	if prop.Class != "" {
		sb.WriteString(" ")
		sb.WriteString(prop.Class)
	}

	return sb.String()
}

// alertIcon returns the appropriate icon component for the variant.
func alertIcon(variant AlertVariant) templ.Component {
	switch variant {
	case AlertSuccess:
		return IconCheck()
	case AlertWarning:
		return IconWarning()
	case AlertDanger:
		return IconX()
	case AlertInfo:
		return IconInfo()
	default:
		return IconInfo()
	}
}

